install_ai_config() {    local target="$HOME/.termux-doctor-ai"    if [ -f "$target" ]; then        echo "[AI] Config already exists at $target"        return    fi    echo "[AI] Installing AI config template..."    cp "$SCRIPT_DIR/../.termux-doctor-ai.template" "$target"    echo "[AI] AI config installed."    echo "Edit $target and replace PUT_YOUR_HF_TOKEN_HERE with your HuggingFace token."}install_ai_config
